# shapes.spy - Interface and abstract base classes for geometric shapes
# Tests: Interface inheritance across modules, abstract classes with virtual methods

interface IScalable:
    """Interface for shapes that can be scaled"""
    def scale(self, factor: float) -> None:
        ...

    def get_scale_factor(self) -> float:
        ...


interface IDrawable:
    """Interface for drawable objects"""
    def draw(self) -> str:
        ...


@abstract
class Shape(IScalable, IDrawable):
    """Abstract base class for all shapes"""
    name: str
    _scale_factor: float

    def __init__(self, name: str):
        self.name = name
        self._scale_factor = 1.0

    @virtual
    def get_area(self) -> float:
        """Calculate area - should be overridden by subclasses"""
        return 0.0

    @virtual
    def describe(self) -> str:
        return f"Shape: {self.name}"

    def scale(self, factor: float) -> None:
        self._scale_factor = factor

    def get_scale_factor(self) -> float:
        return self._scale_factor

    @abstract
    def get_perimeter(self) -> float:
        ...


class Point(Shape):
    """Concrete point class - simplest shape"""
    x: float
    y: float

    def __init__(self, name: str, x: float, y: float):
        super().__init__(name)
        self.x = x
        self.y = y

    @override
    def get_area(self) -> float:
        return 0.0

    @override
    def get_perimeter(self) -> float:
        return 0.0

    @override
    def draw(self) -> str:
        return f"Point({self.x}, {self.y})"

    @override
    def describe(self) -> str:
        return f"Point {self.name} at ({self.x}, {self.y})"

