# utilities.spy - Enums, structs, and utility classes
# Tests: Enum definitions, struct value types, cross-module type usage

enum ShapeType:
    """Classification of shape types"""
    GENERIC = 0
    POLYGON = 1
    CIRCLE = 2
    ELLIPSE = 3
    RECTANGLE = 4


struct Dimensions:
    """Value type for dimensions - copied on assignment"""
    width: float
    height: float

    def __init__(self, w: float, h: float):
        self.width = w
        self.height = h

    def area(self) -> float:
        return self.width * self.height

    def aspect_ratio(self) -> float:
        if self.height == 0.0:
            return 0.0
        return self.width / self.height


class Calculator:
    """Utility class for calculations"""

    @staticmethod
    def calculate_circle_area(radius: float) -> float:
        return 3.14159 * radius * radius

    @staticmethod
    def calculate_circle_perimeter(radius: float) -> float:
        return 2.0 * 3.14159 * radius

    @staticmethod
    def calculate_rectangle_area(width: float, height: float) -> float:
        return width * height

    @staticmethod
    def calculate_rectangle_perimeter(width: float, height: float) -> float:
        return 2.0 * (width + height)

