# extensions.spy - Extended shape classes using inheritance and utilities
# Tests: Cross-module inheritance, using imported structs/enums

from shapes import Shape, IScalable, IDrawable
from utilities import Dimensions, Calculator, ShapeType


class Rectangle(Shape):
    """Rectangle that uses Dimensions struct and Calculator"""
    dims: Dimensions
    shape_type: ShapeType

    def __init__(self, name: str, width: float, height: float):
        super().__init__(name)
        self.dims = Dimensions(width, height)
        self.shape_type = ShapeType.RECTANGLE

    @override
    def get_area(self) -> float:
        scaled: Dimensions = Dimensions(
            self.dims.width * self.get_scale_factor(),
            self.dims.height * self.get_scale_factor()
        )
        return scaled.area()

    @override
    def get_perimeter(self) -> float:
        w: float = self.dims.width * self.get_scale_factor()
        h: float = self.dims.height * self.get_scale_factor()
        return Calculator.calculate_rectangle_perimeter(w, h)

    @override
    def draw(self) -> str:
        return f"Rectangle({self.dims.width}x{self.dims.height})"

    @override
    def describe(self) -> str:
        base: str = super().describe()
        return f"{base} [Type: Rectangle, Aspect: {self.dims.aspect_ratio():.2f}]"


class Circle(Shape):
    """Circle implementation using Calculator"""
    radius: float
    shape_type: ShapeType

    def __init__(self, name: str, radius: float):
        super().__init__(name)
        self.radius = radius
        self.shape_type = ShapeType.CIRCLE

    @override
    def get_area(self) -> float:
        return Calculator.calculate_circle_area(self.radius * self.get_scale_factor())

    @override
    def get_perimeter(self) -> float:
        return Calculator.calculate_circle_perimeter(self.radius * self.get_scale_factor())

    @override
    def draw(self) -> str:
        return f"Circle(r={self.radius})"

    @override
    def describe(self) -> str:
        base: str = super().describe()
        return f"{base} [Type: Circle]"


class Square(Rectangle):
    """Square is a special rectangle with equal sides"""

    def __init__(self, name: str, side: float):
        # Call Rectangle's constructor with equal width/height
        super().__init__(name, side, side)

    @override
    def describe(self) -> str:
        base: str = super().describe()
        return f"{base.replace('Rectangle', 'Square')}"
